{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-compressor-mixed-parameter-patch-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的压缩机、分离器及其下游未连接气相物流生成候选提案，重点处理有直接诊断支撑的局部问题：压缩机出口压力目标低于入口压力、最小流量旁路参数缺失、分离器固定压力目标缺失，以及分离器气相出口未连接。",
  "issues": [
    {
      "title": "压缩机出口压力目标与入口压力关系冲突",
      "detail": "Recycle Compressor 22 采用 outlet_pressure 控制，但当前 outlet_pressure_target_kpa=165 低于入口物流 feed-94 的 190 kPa。",
      "citations": [
        "diag-2",
        "flowdoc-unit-1",
        "flowdoc-stream-1"
      ]
    },
    {
      "title": "压缩机防喘振审查要求的最小流量旁路百分比缺失",
      "detail": "Recycle Compressor 22 的 anti_surge_review_required=true，但缺少 minimum flow bypass percent 参数。",
      "citations": [
        "diag-3",
        "flowdoc-unit-1"
      ]
    },
    {
      "title": "分离器固定压力模式缺少压力目标",
      "detail": "Intermediate Separator 22 配置为 fixed pressure mode，但 operating pressure target 缺失。",
      "citations": [
        "diag-4",
        "flowdoc-unit-2"
      ]
    },
    {
      "title": "分离器气相出口未连接下游去向",
      "detail": "Separator Gas 94 当前没有任何 downstream consumer 或 export sink，且其路由仍依赖当前压缩机排出与分离器压力上下文。",
      "citations": [
        "diag-1",
        "diag-6",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    }
  ],
  "answers": [
    {
      "summary": "针对 compressor-22、separator-22 和 separator-gas-94 提出最小且可审查的候选 patch；其中参数类修补可直接作为占位或局部更新审阅，未连接气相物流仅建议补充连接占位，不假定具体下游对象。",
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 22 提议修正出口压力目标并补充防喘振旁路参数",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "诊断直接表明压缩机出口压力目标低于入口压力，且 anti-surge review 所需的 minimum flow bypass percent 缺失。为保持 patch 最小且非执行式，这里仅提出将无效目标改为高于当前入口压力的待确认占位，并补充缺失参数占位；不在当前证据不足时直接改动效率参数。",
          "patch": {
            "parameter_updates": {
              "outlet_pressure_target_kpa": {
                "mode": "replace_with_placeholder",
                "value_placeholder": {
                  "key": "compressor-22.outlet_pressure_target_kpa",
                  "description": "设为高于 feed-94 当前 190 kPa 入口压力的有效压缩机出口压力目标",
                  "constraints": {
                    "greater_than": 190
                  }
                }
              }
            },
            "parameter_placeholders": [
              {
                "path": "config.minimum_flow_bypass_percent",
                "key": "compressor-22.minimum_flow_bypass_percent",
                "description": "补充防喘振审查要求的最小流量旁路百分比",
                "constraints": {
                  "min": 0,
                  "max": 100
                }
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Intermediate Separator 22 提议补充固定压力目标参数",
          "target": {
            "type": "unit",
            "id": "separator-22"
          },
          "rationale": "分离器已配置为 fixed pressure mode，但缺少 operating pressure target。为避免凭空指定数值，建议仅添加一个待确认的压力目标占位，由审阅者结合当前流程压力层级确认。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.operating_pressure_target_kpa",
                "key": "separator-22.operating_pressure_target_kpa",
                "description": "补充分离器 fixed pressure mode 所需的操作压力目标",
                "constraints": {
                  "unit": "kPa"
                }
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-2"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Separator Gas 94 提议补充下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-gas-94"
          },
          "rationale": "该物流存在明确的未连接诊断，但同时诊断指出其路由依赖当前压缩机排出与分离器压力上下文，因此不能在缺乏更多证据时假定具体接收设备。最小 patch 仅建议增加 downstream consumer 或 export sink 的连接占位，供人工确认实际去向。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-gas-94",
              "missing_end": "downstream",
              "allowed_connection_types": [
                "unit_inlet",
                "export_sink"
              ],
              "description": "为未连接的 Separator Gas 94 指定下游接收端或导出端"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.88
    }
  ],
  "citations": [
    {
      "id": "diag-1",
      "kind": "diagnostic",
      "code": "STREAM_DISCONNECTED",
      "target_type": "stream",
      "target_id": "separator-gas-94"
    },
    {
      "id": "diag-2",
      "kind": "diagnostic",
      "code": "COMPRESSOR_OUTLET_PRESSURE_TARGET_INVALID",
      "target_type": "unit",
      "target_id": "compressor-22"
    },
    {
      "id": "diag-3",
      "kind": "diagnostic",
      "code": "COMPRESSOR_MINIMUM_FLOW_BYPASS_MISSING",
      "target_type": "unit",
      "target_id": "compressor-22"
    },
    {
      "id": "diag-4",
      "kind": "diagnostic",
      "code": "UNIT_PARAMETER_INCOMPLETE",
      "target_type": "unit",
      "target_id": "separator-22"
    },
    {
      "id": "diag-5",
      "kind": "diagnostic",
      "code": "UNIT_PARAMETER_OUT_OF_RANGE",
      "target_type": "unit",
      "target_id": "compressor-22"
    },
    {
      "id": "diag-6",
      "kind": "diagnostic",
      "code": "DOWNSTREAM_STATE_DEPENDENT",
      "target_type": "stream",
      "target_id": "separator-gas-94"
    },
    {
      "id": "flowdoc-stream-1",
      "kind": "artifact_ref",
      "artifact_name": "flowsheet_document",
      "path": "$.content.streams[0]"
    },
    {
      "id": "flowdoc-stream-2",
      "kind": "artifact_ref",
      "artifact_name": "flowsheet_document",
      "path": "$.content.streams[1]"
    },
    {
      "id": "flowdoc-stream-3",
      "kind": "artifact_ref",
      "artifact_name": "flowsheet_document",
      "path": "$.content.streams[2]"
    },
    {
      "id": "flowdoc-unit-1",
      "kind": "artifact_ref",
      "artifact_name": "flowsheet_document",
      "path": "$.content.units[0]"
    },
    {
      "id": "flowdoc-unit-2",
      "kind": "artifact_ref",
      "artifact_name": "flowsheet_document",
      "path": "$.content.units[1]"
    },
    {
      "id": "snapshot-1",
      "kind": "snapshot",
      "solver_status": "invalid_topology",
      "last_updated": "2026-04-16T02:25:00Z"
    }
  ]
}
